INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Multi-job-board distribution$q$, $q$Post jobs once and distribute them to more than 200 job boards and marketplace integrations from a single dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$CareersHub careers site$q$, $q$A customizable, brandable careers page that can be localized into 17 languages for international candidates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Collaborative hiring pipelines$q$, $q$Shared candidate pipelines with team comments, ratings, and structured evaluation forms for hiring managers and interviewers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$AI Screening and Matching Assistants$q$, $q$AI tools that help shortlist and match candidates, with monthly usage credits that scale by plan tier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$ReferralsHub$q$, $q$Built-in employee referral program available on the Advance and Optimize plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Candidate self-scheduling$q$, $q$Lets candidates book their own interview times based on interviewer availability.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Advanced custom reporting$q$, $q$Configurable hiring analytics and reporting, expanded further on the Optimize plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$200+ integrations and mobile app$q$, $q$A broad marketplace of native integrations plus a mobile app for managing hiring on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Combines ATS, careers site, and referral tools in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Strong integration marketplace with 200+ connected apps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Collaborative features make it easy for non-recruiter hiring managers to participate$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Multilingual careers site support (17 languages) suits international hiring$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$AI screening and matching tools reduce manual shortlisting time$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$No public pricing; every plan requires a sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Annual contract required, limiting month-to-month flexibility$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$2024 shift to employee-count-based pricing raised costs for some existing customers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Advanced features like SSO and full AI screening are locked behind the top Optimize tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Add-ons like SMS, WhatsApp hiring, and Journeys carry extra undisclosed fees$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Is Recruitee the same company as Recruit CRM or Recruiterflow?$q$, $q$No. Recruitee, Recruit CRM, and Recruiterflow are three separate, unrelated recruiting software companies despite similar-sounding names.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$How much does Recruitee cost?$q$, $q$Recruitee does not publish per-plan pricing; costs are quoted based on company headcount, chosen plan (Start, Advance, or Optimize), and billing period, with a 20 percent discount for annual payment.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Is Recruitee still called Recruitee?$q$, $q$The product is now branded Tellent Recruitee after a 2022 corporate rename, though most customers still refer to it simply as Recruitee.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Does Recruitee require a long-term contract?$q$, $q$Yes, Recruitee requires a minimum one-year contract, though invoices can be paid monthly or annually.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Can Recruitee's careers site be shown in multiple languages?$q$, $q$Yes, the public careers site and job listings can be localized into 17 languages, even though the internal recruiter dashboard is in English.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$What AI features does Recruitee offer?$q$, $q$Recruitee includes an AI Screening Assistant and AI Matching Assistant, with usage credits that increase on the Advance and Optimize plans, plus AI-assisted email and feedback writing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Who founded Recruitee?$q$, $q$Recruitee was founded in Amsterdam in 2015 by Perry Oostdam and Pawel Smoczyk.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$What company owns Recruitee today?$q$, $q$Recruitee is part of Tellent, formed from a 2021 merger with Finnish HR software provider Sympa and backed by growth equity firm Providence Strategic Growth.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Scaling startup hiring$q$, $q$Replacing spreadsheets and inbox-based hiring with a shared, structured candidate pipeline as headcount grows.$q$, $q$HR leads and founders at 20-500 person startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Multilingual careers sites for international teams$q$, $q$Presenting job listings and application flows in a candidate's local language across multiple European markets.$q$, $q$Companies hiring across multiple countries or regions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Collaborative hiring for non-recruiter stakeholders$q$, $q$Giving hiring managers and interview panels a shared space to score and discuss candidates without ATS training.$q$, $q$Hiring managers and interview panel members$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Start$q$, $q$Custom quote$q$, $q$Monthly or annual (1-year minimum contract)$q$, NULL, $q$["Up to 5 active job postings","Single-page CareersHub careers site","Multi-job board posting and team collaboration tools","Candidate management with pipeline automation","AI-powered email and feedback writing","Mobile app and 200+ marketplace integrations","Unlimited data storage","Live chat support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Advance$q$, $q$Custom quote$q$, $q$Monthly or annual (1-year minimum contract)$q$, NULL, $q$["All Start features plus unlimited job posts","Multi-page, branded careers site","Employee referrals program (ReferralsHub)","AI Screening Assistant (100 credits per month)","AI Matching Assistant (3 searches per month)","Knockout questions and workflow automations","Candidate self-scheduling and structured evaluation forms","Advanced custom reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Optimize$q$, $q$Custom quote$q$, $q$Monthly or annual (1-year minimum contract)$q$, NULL, $q$["All Advance features plus SSO and dedicated CSM","Full AI Screening Assistant functionality","AI Matching Assistant (65 searches per month)","Conditional workflow automations","Fairness tools for unbiased hiring","Requisition approval workflows","Unlimited custom fields","Testing environment and BI integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Recruitee, founded in Amsterdam in 2015 and now sold as Tellent Recruitee, is a cloud-based applicant tracking system built to give small and mid-sized companies a shared, collaborative hiring pipeline instead of managing recruitment through spreadsheets and email. It combines job distribution, a branded careers site, and candidate pipeline management in a single platform used by more than 7,000 companies globally.$q$, $q$Following a 2021 merger with Finnish HR provider Sympa and further acquisitions in 2022, Recruitee now operates as a product line within the Tellent group, backed by growth equity firm Providence Strategic Growth.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Recruitee centers on collaborative hiring: hiring managers, recruiters, and interviewers can comment on and score candidates within a shared pipeline, supported by structured evaluation forms, knockout questions, and candidate self-scheduling for interviews. The platform distributes jobs to more than 200 job boards and integration partners and offers a customizable CareersHub careers site that can be localized into 17 languages.$q$, $q$Higher tiers add AI-assisted features, including an AI Screening Assistant and AI Matching Assistant with monthly usage credits, an employee referral program called ReferralsHub, advanced custom reporting, and enterprise controls like single sign-on and requisition approval workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Recruitee sells three tiers, Start, Advance, and Optimize, none of which have publicly listed prices; the company quotes cost based on a prospect's employee headcount, chosen plan, and billing period. A minimum one-year contract is required, though invoices can be paid monthly, and paying annually earns a 20 percent discount.$q$, $q$Optional add-ons priced separately from the base plan include SMS texting, WhatsApp-based candidate outreach, an onboarding tool called Journeys, and AgencyHub for managing external recruitment agencies, so total cost can vary significantly between customers with similar headcounts.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Combined ATS and CRM$q$, $q$Unified candidate and client pipeline management built specifically for agency recruiting workflows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Multichannel outreach sequences$q$, $q$Automated candidate and client outreach across email and other channels.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Recipes recruiting automation$q$, $q$Configurable automation workflows that handle repetitive recruiting tasks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$AIRA AI recruiting agent$q$, $q$AI notetaker, candidate matchmaker, job-change alerts, and automated submission and task agents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Bulk sourcing Chrome extension$q$, $q$Sources candidates in bulk directly from LinkedIn and other websites.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Sales automation$q$, $q$Automation tools for business development and client acquisition.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Custom reporting and API access$q$, $q$Configurable reports and API access for integrating with other agency tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Client and team access controls$q$, $q$Granular permissions for managing which team members and clients see which data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Purpose-built for agency recruiting workflows, combining ATS and CRM in one tool$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Bootstrapped and profitable, suggesting business stability$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Unlimited jobs, candidates, contacts, and companies included on every plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$AIRA AI agent bundles many automation features without extra add-on fees$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$14-day full-feature free trial, including live outbound campaigns$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Per-seat pricing with a 3-seat minimum can be costly for very small agencies$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$AIRA plan pricing is not published and requires a sales quote$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Primarily built for staffing and agency recruiting, less suited to corporate in-house TA teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Interface and support are limited to English$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Is Recruiterflow the same as Recruitee or Recruit CRM?$q$, $q$No. Recruiterflow, Recruitee, and Recruit CRM are three separate, unrelated recruiting software companies with similar-sounding names.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$How much does Recruiterflow cost?$q$, $q$As of 2026, Recruiterflow's Platform plan is priced at 149 dollars per user per month, with a 3-seat minimum, while the AI-enabled AIRA plan is custom priced.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Does Recruiterflow offer a free trial?$q$, $q$Yes, Recruiterflow offers a 14-day free trial with full feature access, including outbound campaigns and candidate database import.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Who is Recruiterflow built for?$q$, $q$Recruiterflow is built primarily for recruitment and staffing agencies, executive search firms, and RPO teams rather than in-house corporate talent acquisition teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$What is AIRA?$q$, $q$AIRA is Recruiterflow's AI recruiting agent suite, including an automatic call notetaker, candidate matchmaker, job-change alerts, and automated submission and task agents.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Is Recruiterflow venture-funded?$q$, $q$No, Recruiterflow has stated it is a bootstrapped company that has grown to tens of millions of dollars in annual recurring revenue without outside venture funding.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Where is Recruiterflow based?$q$, $q$Recruiterflow is headquartered in San Francisco, California, and was founded in 2017.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Is there a minimum number of seats required?$q$, $q$Yes, all Recruiterflow plans require a minimum of 3 seats per account.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Agency recruiter pipeline management$q$, $q$Managing candidate sourcing, client relationships, and placements in one connected pipeline.$q$, $q$Recruitment and staffing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Executive search candidate relationship management$q$, $q$Tracking long-term candidate and client relationships across multiple search engagements.$q$, $q$Executive search and retained search firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Automated candidate sourcing and outreach$q$, $q$Using bulk sourcing tools and multichannel sequences to fill roles faster.$q$, $q$Recruiters and sourcers at agencies scaling outreach volume$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$Platform$q$, $q$$149/user/month$q$, $q$Monthly or annual (3-seat minimum)$q$, NULL, $q$["ATS and CRM","Multichannel sequences","Recruitment automation via Recipes","Sales automation","Client and team access controls","Bulk sourcing via Chrome extension","Reports","API access","Unlimited jobs, candidates, contacts, and companies"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$AIRA$q$, $q$Custom pricing$q$, $q$Monthly or annual (3-seat minimum)$q$, NULL, $q$["All Platform plan features","AIRA Notetaker (automatic call summaries)","AIRA Matchmaker","AIRA Job Change Alerts","AIRA Field Updates Agent","AIRA Submission Agent","AIRA Task Agent","Omnichannel communication sync","Custom BI dashboards"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Recruiterflow is a recruitment CRM and ATS built for staffing agencies, executive search firms, and RPO teams, founded in 2017 and headquartered in San Francisco. The company has grown as a bootstrapped, profitable business without outside venture funding, reportedly serving agencies across more than 90 countries.$q$, $q$Rather than separating sales and recruiting tools, Recruiterflow combines candidate sourcing, client relationship management, and hiring pipeline tracking into one platform, positioning itself specifically against other agency-focused tools rather than corporate in-house ATS platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes a combined ATS and CRM, multichannel outreach sequences, a Chrome extension for bulk candidate sourcing, sales automation for new business development, and recruiting workflow automation the company calls Recipes.$q$, $q$Recruiterflow's AIRA plan adds an AI recruiting agent suite: an automatic call notetaker, candidate matchmaker, job-change alerts, automated field updates, submission and task agents, omnichannel communication syncing, and custom BI dashboards, all bundled without extra add-on fees.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1cdadd8-bcfb-4fe7-a40d-88b82d009576', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Recruiterflow's Platform plan is priced at 149 dollars per user per month, with monthly or annual billing options and a minimum of 3 seats per account. Both the Platform and AIRA plans include unlimited jobs, candidates, contacts, and companies.$q$, $q$The AIRA plan, which layers Recruiterflow's AI recruiting agent tools on top of the Platform plan, is custom priced and quoted directly by the sales team. A 14-day free trial with full feature access is available before committing to either plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Automated global subscription billing$q$, $q$Handles recurring invoicing, proration, and plan changes across currencies and regions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Flexible plan and pricing configuration$q$, $q$Supports complex pricing models, plan changes, and promotional pricing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$AI-powered churn prevention and dunning$q$, $q$Automated retry logic and dunning campaigns to recover failed payments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Payments orchestration$q$, $q$Routes payments across more than 20 gateways and 10+ payment methods.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Multicurrency support and SSO$q$, $q$Global currency support plus single sign-on on higher-tier plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$RevRec revenue recognition$q$, $q$Add-on product automating multi-GAAP-compliant revenue recognition and contract modifications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Engage retention tooling$q$, $q$AI-driven churn prediction, personalized offers, and A/B testing for retention campaigns.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Hosted subscriber portal$q$, $q$Passwordless, self-serve portal for subscribers to manage billing, available on the Shopify plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Mature, well-established platform founded in 2009 with enterprise-grade reliability$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Strong churn-prevention and dunning tooling built into the core product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Dedicated Shopify-focused subscription commerce plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Add-on products (Engage, RevRec) extend beyond core billing into retention and revenue recognition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Broad payment method and gateway support for global billing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Percentage-of-billing-volume pricing can get expensive as revenue scales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$All-Access tier requires a 1 million dollar minimum annual billing volume$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Pricing is not fully self-serve or transparent for higher tiers and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Engage and RevRec are priced and sold separately from core billing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Who owns Recurly?$q$, $q$Recurly has been majority-owned by the private equity firm Accel-KKR since a 2020 investment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$When was Recurly founded?$q$, $q$Recurly was founded in September 2009 in San Francisco by Isaac Hall, Dan Burkhart, and Tim Van Loan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$How much does Recurly cost?$q$, $q$Recurly's Starter plan costs 249 dollars per month plus 0.9 percent of billing volume; higher tiers are priced as a percentage of billing volume with a 1 million dollar minimum.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Does Recurly work with Shopify?$q$, $q$Yes, Recurly offers a dedicated All-Access for Shopify plan for merchants selling subscription products.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$What is Recurly Engage?$q$, $q$Engage is Recurly's separately priced, AI-driven churn prediction and retention product, starting at 1,600 dollars per month.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$What is Recurly RevRec?$q$, $q$RevRec is Recurly's automated revenue recognition and compliance product, starting at 850 dollars per month.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$How big is Recurly?$q$, $q$Recurly has an estimated 200 to 350-plus employees as of 2026, according to various data providers.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$What companies has Recurly acquired?$q$, $q$Recurly has acquired Redfast, Prive, and LeapRev to expand its churn-prevention and analytics capabilities.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Mid-market SaaS subscription billing$q$, $q$Automating recurring invoicing, plan changes, and dunning for growing SaaS companies.$q$, $q$SaaS finance and billing operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Shopify subscription commerce$q$, $q$Launching and managing subscribe-and-save or membership products on Shopify.$q$, $q$DTC and e-commerce merchants on Shopify$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Enterprise revenue recognition compliance$q$, $q$Automating multi-GAAP-compliant revenue recognition for complex subscription contracts.$q$, $q$Finance and accounting teams at larger subscription businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Starter$q$, $q$$249/month + 0.9% of billing volume$q$, $q$Monthly$q$, NULL, $q$["Automated global subscription billing","Flexible plans and pricing","Static churn-prevention tools","1 dunning campaign","10+ payment methods","20+ payment gateways"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$All-Access$q$, $q$Under 1% of billing volume (minimum $1M annual billing volume)$q$, $q$Annual$q$, NULL, $q$["Everything in Starter","AI-powered agents and analytics","Intelligent churn-prevention tools","Multiple dunning campaigns","Advanced plans, pricing, and promotions","Payments orchestration","Custom reporting","Multicurrency support","Single sign-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$All-Access for Shopify$q$, $q$Under 1% of billing volume$q$, $q$Annual$q$, NULL, $q$["Intelligent churn-prevention","Customized bundles","Subscribe and save","Prepaid and gift subscriptions","Hybrid subscription support","Cancel-save flows","Self-serve bulk updater","Hosted subscriber portal with passwordless login"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Engage (add-on)$q$, $q$From $1,600/month$q$, $q$Annual$q$, NULL, $q$["AI propensity-to-churn modeling","1-click billing integration","Personalized offers","Cancel-save and upsell flows","A/B testing","Segmentation","Low-code prompt builder"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$RevRec (add-on)$q$, $q$From $850/month$q$, $q$Annual$q$, NULL, $q$["Automated contract modifications","Standalone selling price automation","Rules-driven allocations","Real-time revenue insights","Automated monthly close","Multi-GAAP compliance"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Recurly is a subscription billing and revenue platform founded in 2009 in San Francisco, where it remains headquartered. Since a 2020 majority equity investment from private equity firm Accel-KKR, Recurly has continued to grow through acquisitions of companies like Redfast, Prive, and LeapRev.$q$, $q$The platform serves subscription-based businesses that need automated recurring billing, churn prevention, and revenue reporting, positioning itself against competitors like Chargebee and Zuora for mid-market and larger subscription companies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Recurly's core billing product covers automated global subscription billing, flexible pricing and plan configuration, dunning campaigns for failed payments, and support for more than 10 payment methods and 20+ payment gateways. Higher tiers add AI-powered churn prediction, payments orchestration, custom reporting, and single sign-on.$q$, $q$Beyond core billing, Recurly sells Engage for AI-driven retention and upsell campaigns, and RevRec for automated, multi-GAAP-compliant revenue recognition, letting subscription businesses handle billing, retention, and accounting compliance within one vendor relationship.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Recurly's Starter plan costs 249 dollars per month plus 0.9 percent of billing volume, with the first 40,000 dollars of monthly volume included. The All-Access plan is priced at under 1 percent of billing volume, billed annually, but requires a minimum of 1 million dollars in annual billing volume.$q$, $q$A separate All-Access for Shopify plan targets subscription commerce merchants, while Engage and RevRec are sold as add-on products starting at 1,600 dollars and 850 dollars per month respectively, both billed annually.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Recurring evergreen content scheduling$q$, $q$Build libraries of approved posts that automatically republish on a set schedule.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Bulk CSV scheduling$q$, $q$Upload and schedule large batches of posts at once with no stated limit.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Visual content calendar and best-time scheduler$q$, $q$Drag-and-drop calendar with recommendations for optimal posting times.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$AI captions, images, and hashtags$q$, $q$AI-generated captions and images plus hashtag suggestions built into the composer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Client workspaces$q$, $q$Password-free client onboarding and separate workspaces per client on the Agency plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$White-label analytics reporting$q$, $q$Branded reports for agencies to share with their own clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Built-in image editor and stock library$q$, $q$Edit images and access a royalty-free stock photo library directly in the composer.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Ten supported networks$q$, $q$Facebook, Instagram, LinkedIn, X, Google Business Profile, Pinterest, TikTok, YouTube, Threads, and Bluesky.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Low entry price point starting at $9/month$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Recurring content library differentiates it from simple one-off schedulers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Dedicated Agency tier with client workspaces and white-label reports$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Supports 10 social networks including newer platforms like Threads and Bluesky$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$30-day money-back guarantee and 14-day free trial$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$No permanent free plan anymore$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Lower tiers cap accounts, users, and daily posts fairly tightly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Extra accounts and teammates cost additional a la carte fees$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Interface is English-only$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Does RecurPost have a free plan?$q$, $q$No, RecurPost discontinued its free plan and now offers a 14-day free trial instead across four paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$How much does RecurPost cost?$q$, $q$Plans start at 9 dollars per month for the Starter tier and range up to 79 dollars per month for the Agency tier, with custom Enterprise pricing above that.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$What does recurring mean in RecurPost?$q$, $q$RecurPost lets users build libraries of evergreen posts that automatically republish on a set schedule, in addition to standard one-off scheduling.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Which social networks does RecurPost support?$q$, $q$RecurPost supports Facebook, Instagram, LinkedIn, X, Google Business Profile, Pinterest, TikTok, YouTube, Threads, and Bluesky.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Is RecurPost good for agencies?$q$, $q$Yes, the Agency plan adds separate client workspaces, password-free client onboarding, approval workflows, and white-label reporting.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Who founded RecurPost?$q$, $q$RecurPost was founded in 2016 by Dinesh Agarwal.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Where is RecurPost based?$q$, $q$RecurPost is headquartered in Winder, Georgia, in the United States.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Solo marketer evergreen content scheduling$q$, $q$Building recurring post libraries so content keeps publishing without manual re-scheduling.$q$, $q$Solo marketers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Agency multi-client social management$q$, $q$Managing separate workspaces, approvals, and white-label reports for multiple clients.$q$, $q$Social media agencies and freelance social managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Small business bulk content calendar planning$q$, $q$Planning and scheduling weeks or months of content at once via CSV upload and a visual calendar.$q$, $q$Small business marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Starter$q$, $q$$9/month$q$, $q$Monthly (annual billing saves ~2 months)$q$, NULL, $q$["2 social accounts","1 user","10 posts per day per account","Recurring and one-off scheduling","Best-time scheduler","Composer with built-in image editor"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Personal$q$, $q$$25/month$q$, $q$Monthly (annual billing saves ~2 months)$q$, NULL, $q$["5 social accounts","1 user","20 posts per day per account","Platform-specific post customization","Post variations and seasonal libraries","2 shareable calendars","Chrome extension"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Agency$q$, $q$$79/month$q$, $q$Monthly (annual billing saves ~2 months)$q$, NULL, $q$["20 social accounts","3 users (owner plus 2)","80 posts per day per account","Password-free client onboarding","Separate client workspaces","Approval workflows","White-label analytics reports","10+ AI features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["100+ social accounts","Custom user limits","Custom daily post limits","Reduced bulk add-on pricing","Priority support","Sales-assisted implementation"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RecurPost is a social media scheduling platform founded in 2016 by Dinesh Agarwal and headquartered in Winder, Georgia. It is best known for its recurring, evergreen content libraries, letting users schedule posts that automatically republish on a set cadence rather than needing to be recreated repeatedly.$q$, $q$The company reports serving more than 100,000 businesses and is bootstrapped, with reported annual revenue figures ranging from roughly 5.3 million to 27 million dollars depending on the source and reporting year.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond recurring content scheduling, RecurPost offers a visual content calendar, best-time-to-post recommendations, bulk CSV upload, and a composer with a built-in image editor, AI-generated captions and images, and hashtag suggestions. It connects to ten networks including Facebook, Instagram, LinkedIn, X, TikTok, and Bluesky.$q$, $q$Agency-focused features include separate client workspaces, password-free client onboarding, internal and external approval workflows, and white-label analytics reports, making it suitable for teams managing multiple client accounts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('410b0dd0-b940-4829-8aac-3c86129e1d0d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RecurPost no longer offers a permanent free plan, but provides a 14-day free trial with no credit card required across four tiers: Starter at 9 dollars per month, Personal at 25 dollars per month, Agency at 79 dollars per month, and custom-priced Enterprise.$q$, $q$Annual billing saves roughly two months compared with monthly billing, additional social accounts can be added for 4 dollars per month, and extra Agency-plan teammates cost 20 dollars per month; new subscriptions include a 30-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Parkour-focused movement$q$, $q$Fast running, wall-running, and sliding mechanics layered onto traditional arena shooter combat.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Tesseract engine graphics$q$, $q$Deferred shading, improved shadow mapping, and reflection and refraction support.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Real-time in-game level editor$q$, $q$Full multiplayer map editor built into the game, usable by any player.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Multiple competitive game modes$q$, $q$Free-for-all and team-based modes including King of the Hill and cooperative editing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Cross-platform support$q$, $q$Runs natively on Windows, macOS, and Linux.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$No monetization$q$, $q$Completely free with no in-game purchases, ads, or subscriptions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Open-source codebase$q$, $q$Full source code available under the permissive zlib license.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Active modding community$q$, $q$Community-driven map creation and modification using the built-in editor.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Completely free with no monetization or paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Fully open source, allowing community modding and code audits$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Fast, skill-based parkour movement sets it apart from typical arena shooters$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Built-in level editor lets players create and share custom maps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Available cross-platform on Windows, macOS, and Linux$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Smaller, niche player base compared to mainstream commercial shooters$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$No official mobile or console versions$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Steeper learning curve due to fast movement mechanics$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Volunteer-driven development means a slower, less predictable update cadence$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Is Red Eclipse 2 really free?$q$, $q$Yes, Red Eclipse 2 is completely free to download and play, with no in-game purchases or subscription required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$What engine does Red Eclipse 2 use?$q$, $q$Red Eclipse 2 runs on the Tesseract engine, an open-source fork of the Cube 2 engine written by developer Lee Salzman.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$When was Red Eclipse 2 released?$q$, $q$Red Eclipse 2.0, called the Jupiter Edition, was released on Steam on December 19, 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Is Red Eclipse 2 open source?$q$, $q$Yes, the game is free and open-source software released under the permissive zlib license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$What platforms does Red Eclipse 2 support?$q$, $q$Red Eclipse 2 runs on Windows, macOS, and Linux, and is available via Steam, itch.io, and direct download.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Does Red Eclipse 2 have a level editor?$q$, $q$Yes, it includes a full real-time, in-game multiplayer level editor built on the Tesseract engine.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Who develops Red Eclipse 2?$q$, $q$It is developed by an open community of volunteer contributors, including original developers Quinton Reeves, Lee Salzman, and Slawomir Blauciak.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$What was the original Red Eclipse based on?$q$, $q$Red Eclipse was originally forked from Cube 2: Sauerbraten before adopting the Tesseract engine for its 2.0 release.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Free competitive arena shooter for FPS fans$q$, $q$Playing fast, parkour-based multiplayer matches without any cost or purchase requirement.$q$, $q$FPS players looking for a free, skill-based shooter$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Level design and modding practice$q$, $q$Using the built-in real-time editor to design and share custom multiplayer maps.$q$, $q$Aspiring level designers and modders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Open-source game engine study for developers$q$, $q$Reviewing and modifying the publicly available Tesseract-based source code.$q$, $q$Developers studying open-source game engines$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$Red Eclipse 2$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full game access with no purchase required","Unlimited multiplayer and singleplayer play","Built-in real-time level editor","Open-source code under the zlib license","Regular community-driven updates"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Red Eclipse 2 is a free, open-source first-person shooter forked from Cube 2: Sauerbraten and developed by a volunteer community rather than a commercial studio. Its first stable release launched in March 2011, and the major 2.0 Jupiter Edition, built on the more advanced Tesseract engine, arrived on Steam in December 2019.$q$, $q$The game is defined by fast, parkour-style movement through vertical multiplayer arenas, along with a built-in real-time level editor that gives players the same map-building tools the developers use themselves.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Red Eclipse 2 runs on the Tesseract engine, adding deferred shading, improved shadow mapping, and reflection and refraction support compared with earlier versions. Gameplay centers on agile, skill-based movement, including running, wall-running, and sliding, layered on top of multiple competitive modes.$q$, $q$The included real-time multiplayer level editor lets players create and modify maps directly inside the game, and the title is fully cross-platform, running natively on Windows, macOS, and Linux.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59de2787-72b5-4f39-9d09-b260b1994aa6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Red Eclipse 2 is completely free to download and play, with no premium edition, in-game purchases, or subscription of any kind. It is released under the permissive zlib open-source license, so its full source code is publicly available for anyone to inspect, modify, and redistribute.$q$, $q$The game can be downloaded through Steam, itch.io, or directly from the official redeclipse.net website at no cost, and ongoing development is funded and driven entirely by volunteer community contributions rather than commercial revenue.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Broad database and API connectors$q$, $q$Connects to dozens of relational databases, NoSQL stores, and third-party APIs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Web-based SQL query editor$q$, $q$Browser-based SQL editor with autocomplete for writing and sharing queries.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Chart and visualization builder$q$, $q$Turns query results into charts and visualizations without extra tooling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Shareable dashboards$q$, $q$Combines multiple queries and visualizations into a single shareable dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Scheduled refresh and alerting$q$, $q$Automatically refreshes queries on a schedule and can alert on result thresholds.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Query result caching$q$, $q$Caches query results to improve dashboard load performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$User and permission management$q$, $q$Role-based access controls for self-hosted team deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Open-source, self-hostable via Docker$q$, $q$Deployable on your own infrastructure with no licensing fee.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Completely free to self-host with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Broad database and data source connector support$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Simple, SQL-first workflow familiar to analysts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Large existing community and long GitHub history$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Backed historically by well-known companies as users, including Atlassian and Mozilla$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$The original hosted Redash Cloud service was shut down by Databricks in November 2021$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Development has slowed to roughly one release per year since the acquisition$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Self-hosting requires infrastructure setup and ongoing maintenance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Feature development has lagged behind actively developed alternatives like Metabase and Superset$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$No official commercial support channel independent of the community$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Is Redash still free?$q$, $q$Yes, the self-hosted, open-source version of Redash remains free to use; only infrastructure hosting costs apply.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Who owns Redash now?$q$, $q$Databricks acquired Redash in June 2020, and the project remains under Databricks' umbrella, though development has slowed considerably.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Is the hosted Redash Cloud still available?$q$, $q$No, Databricks shut down the original hosted Redash Cloud service at app.redash.io on November 30, 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Is Redash actively developed?$q$, $q$Development has slowed significantly since the Databricks acquisition, averaging roughly one release per year since 2022, and the project is widely considered to be in maintenance mode.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Who created Redash?$q$, $q$Redash was created in 2013 by Arik Fraimovich in Israel.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$What can Redash connect to?$q$, $q$Redash connects to a wide range of relational databases, NoSQL stores, and APIs to run SQL queries and build dashboards.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Are there paid Redash hosting options?$q$, $q$Yes, some third-party providers offer managed Redash hosting, typically starting around 49 dollars per month, though these are unaffiliated with Databricks.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$What are alternatives to Redash?$q$, $q$Common alternatives include Metabase, Apache Superset, and Databricks' own native dashboarding tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Self-hosted SQL dashboards for small data teams$q$, $q$Running lightweight, self-hosted dashboards without enterprise BI licensing costs.$q$, $q$Small data and analytics teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Lightweight BI for startups avoiding enterprise BI licensing costs$q$, $q$Using a free, open-source tool instead of paying for a full commercial BI platform.$q$, $q$Early-stage startups with limited budgets$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Legacy Redash deployments maintained by existing users$q$, $q$Continuing to run and maintain existing self-hosted Redash instances after the Databricks acquisition.$q$, $q$Organizations with pre-existing Redash deployments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Self-Hosted Open Source$q$, $q$Free (infrastructure hosting costs typically $5 to $10/month)$q$, $q$N/A$q$, NULL, $q$["Full open-source Redash codebase","Connectors to dozens of data sources","Unlimited users on self-hosted infrastructure","Community support only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$Third-Party Managed Hosting$q$, $q$From approximately $49/month$q$, $q$Monthly$q$, NULL, $q$["Managed infrastructure from unaffiliated hosting providers","Automatic updates and backups","Not officially affiliated with Databricks"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Redash is an open-source SQL query and dashboarding tool created in 2013 by Arik Fraimovich in Israel, later acquired by Databricks in June 2020. It lets teams connect to many databases and APIs, write shared SQL queries, and turn results into charts and dashboards.$q$, $q$Databricks shut down the original hosted Redash Cloud service in late 2021, and while the open-source self-hosted project remains free and usable, its development pace has slowed considerably, with roughly one release per year since 2022.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Redash connects to dozens of relational databases, NoSQL stores, and APIs, offering a web-based SQL editor with autocomplete, a chart and visualization builder, and the ability to combine multiple queries into shareable dashboards.$q$, $q$Additional capabilities include scheduled query refresh, alerting on query results, result caching for performance, and user and permission management for teams running self-hosted deployments, typically via Docker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4fe35bb-b786-4c89-83e9-c43385bfe93b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Redash's self-hosted, open-source version is free to deploy, with only infrastructure hosting costs applying, typically estimated at 5 to 10 dollars per month for a small to medium instance depending on database and usage scale.$q$, $q$The original Databricks-hosted Redash Cloud service was shut down in November 2021, but unaffiliated third-party providers now offer separate managed Redash hosting plans, typically starting around 49 dollars per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Modular content architecture$q$, $q$Custom modules and templates give developers full control over HTML, CSS, and PHP output.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Multilingual website support$q$, $q$Built-in support for multilingual content trees and translated pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Granular user rights and roles$q$, $q$Configurable permission system defining exactly what each backend user can access.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Media and file management$q$, $q$Structured management of multimedia content and uploaded files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$MIT-licensed open-source codebase$q$, $q$Freely usable, modifiable, and commercially deployable at no cost.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Composer and GitHub-based workflow$q$, $q$Installable and maintainable via Composer, with source hosted on GitHub.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Friends of REDAXO add-on ecosystem$q$, $q$A volunteer community maintaining free add-ons, modules, and translations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Multilingual backend interface$q$, $q$Available in German, English, Spanish, Italian, Swedish, and Portuguese.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Completely free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Highly modular, giving developers full control over markup and structure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Strong, mature community (Friends of REDAXO) with many free add-ons$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Granular, configurable permission system for editorial teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Multilingual out of the box, both for content and the backend interface$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Long track record since 2004 with active ongoing maintenance$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Primarily documented and discussed in German, which can be a barrier for non-German developers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Requires PHP development knowledge and is not a no-code website builder$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Smaller global ecosystem and plugin marketplace compared to WordPress$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$No official enterprise support contract from a single vendor$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Is REDAXO free?$q$, $q$Yes, REDAXO is completely free and open source under the MIT license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Who maintains REDAXO?$q$, $q$REDAXO is maintained by the German agency Yakamara Media in Frankfurt am Main, together with a volunteer community called Friends of REDAXO.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$What technology does REDAXO use?$q$, $q$REDAXO is built on PHP and uses MySQL or MariaDB as its database.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Is REDAXO good for beginners?$q$, $q$REDAXO is aimed at developers and agencies comfortable with PHP and templating, rather than no-code website builders.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$What languages does REDAXO's backend support?$q$, $q$The REDAXO backend is available in German, English, Spanish, Italian, Swedish, and Portuguese.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$When was REDAXO released as open source?$q$, $q$REDAXO was developed internally starting in 1999 and released publicly as open-source software in 2004.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$What license does REDAXO use?$q$, $q$REDAXO switched from the GNU GPL to the more permissive MIT license in 2016.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Can REDAXO be used commercially?$q$, $q$Yes, the MIT license permits free commercial use, modification, and redistribution.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Custom multilingual corporate websites$q$, $q$Building fully custom, multilingual corporate sites with precise control over markup.$q$, $q$Web developers building corporate or institutional sites$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Agency-built client sites needing granular editor permissions$q$, $q$Giving client editorial teams tightly scoped access to only the content they should manage.$q$, $q$Web agencies managing multiple client sites$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$Developer-controlled PHP CMS projects avoiding page-builder bloat$q$, $q$Building lightweight, code-first websites without the overhead of larger commercial CMS platforms.$q$, $q$Freelance PHP developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$REDAXO CMS$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source CMS core under the MIT license","Unlimited installations and websites","Access to community-built add-ons via Friends of REDAXO","No user or site limits"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$REDAXO is a free, open-source PHP content management system developed since 1999 by the German agency Yakamara in Frankfurt am Main and released publicly as open source in 2004. It switched from the GNU GPL to the more permissive MIT license in 2016.$q$, $q$Development is community-driven, led by Yakamara's core team alongside Friends of REDAXO, a volunteer association of independent developers and agencies that contribute modules, translations, and core improvements.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$REDAXO centers on a modular content architecture where developers build custom modules and templates with full control over HTML, CSS, and PHP output, separating layout from content for non-technical editors. It supports fully multilingual websites and content trees, plus structured media and file management.$q$, $q$A granular, configurable user rights and role system lets administrators define exactly what each backend user can see and edit, and the backend interface itself is available in German, English, Spanish, Italian, Swedish, and Portuguese.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfc00fd3-6190-4930-b4d3-4453015d69ed', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$REDAXO is entirely free and open source under the MIT license, with no pricing tiers, subscription plans, or paid editions of the core software.$q$, $q$The surrounding ecosystem is supported through community contributions and sponsorships, while independent web agencies that specialize in REDAXO separately offer paid implementation, customization, and hosting services.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Free Core plan with unlimited storage$q$, $q$One podcast with unlimited storage, bandwidth, episodes, and downloads at no cost.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$RedCircle Ad Platform marketplace$q$, $q$Built-in marketplace for host-read and programmatic ad opportunities.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Dynamic ad insertion$q$, $q$Automatically refreshes ads on older episodes as they continue to be downloaded.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Cross-promotion marketplace$q$, $q$Connects podcasters for mutual audience promotion swaps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Listener donations and exclusive content$q$, $q$Built-in tools for direct listener support and gated bonus content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$RSS feed import$q$, $q$Migrate an existing show to RedCircle without losing episode history.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$AI video generation and YouTube distribution$q$, $q$Turns episodes into video content and distributes them to YouTube on Growth and Pro plans.$q$, 6);
