INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Creator-favorable revenue splits of 70 percent on host-read and 50 percent on programmatic ads$q$, 1);
