INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Ad marketplace access requires reaching 500 or more weekly downloads$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Hosting multiple podcasts requires a paid Growth plan or higher$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Higher tiers (Pro, Enterprise) can get costly for hobbyist podcasters$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Team collaboration with multiple seats is limited to Pro and Enterprise plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Is RedCircle really free?$q$, $q$Yes, the Core plan is entirely free and includes one podcast with unlimited storage, bandwidth, episodes, and downloads.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$How much are RedCircle's paid plans?$q$, $q$Growth costs 19.99 dollars per month, Pro costs 34.99 dollars per month, and Enterprise costs 119.99 dollars per month, each with a lower effective rate on annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$How does RedCircle monetization work?$q$, $q$Podcasters can earn through listener donations, exclusive content, and the RedCircle Ad Platform, keeping 70 percent of host-read ad revenue and 50 percent of programmatic ad revenue.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$What downloads threshold is needed to join the ad marketplace?$q$, $q$Shows need at least 500 weekly downloads to become eligible for the RedCircle Ad Platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Can I move my existing podcast to RedCircle?$q$, $q$Yes, RedCircle supports RSS feed import to migrate an existing show without losing episode history.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Who founded RedCircle?$q$, $q$RedCircle was founded in 2018 by Mike Kadin and Jeremy Lermitte.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Does RedCircle offer a free trial on paid plans?$q$, $q$Yes, all paid plans include a 7-day free trial.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Where is RedCircle based?$q$, $q$RedCircle is headquartered in Los Angeles, California.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Independent podcaster monetization$q$, $q$Earning ad revenue, donations, and exclusive-content income without a separate ad sales relationship.$q$, $q$Independent and semi-professional podcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Multi-show podcast network hosting$q$, $q$Hosting and managing multiple shows under paid plans with centralized analytics.$q$, $q$Small podcast networks and multi-show creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Podcast audience growth via cross-promotion$q$, $q$Using the cross-promotion marketplace to swap audience exposure with other shows.$q$, $q$Growth-focused podcasters seeking new listeners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 podcast with unlimited storage, bandwidth, episodes, and downloads","Distribution to major listening platforms","Listener donations and exclusive content","RAP ad marketplace eligibility at 500+ weekly downloads","Standard analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Growth$q$, $q$$19.99/month or $180/year$q$, $q$Monthly or annual$q$, NULL, $q$["All Core features","Multiple podcasts","AI video generation","5 episode transcripts per month","Cross-promotion marketplace","Dynamic ad insertion and custom dynamic insertion","Advanced analytics with export"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Pro$q$, $q$$34.99/month or $360/year$q$, $q$Monthly or annual$q$, NULL, $q$["All Growth features","Premium analytics","YouTube distribution","50 episode transcripts per month","Team seats for up to 5 additional users"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$Enterprise$q$, $q$$119.99/month or $1,199/year$q$, $q$Monthly or annual$q$, NULL, $q$["All Pro features","Dedicated account manager","Comprehensive analytics","500 episode transcripts per month"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RedCircle is a podcast hosting and monetization platform founded in 2018 by Mike Kadin and Jeremy Lermitte and headquartered in Los Angeles. The company raised a 6 million dollar Series A round co-led by EPIC Ventures and Refinery Ventures.$q$, $q$RedCircle is best known for pairing genuinely free unlimited-storage hosting with a built-in advertising marketplace, letting independent podcasters monetize without a separate ad sales relationship.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The RedCircle Ad Platform offers both host-read and programmatic advertising opportunities once a show reaches 500 weekly downloads, with podcasters keeping 70 percent of host-read revenue and 50 percent of programmatic revenue. Dynamic ad insertion automatically refreshes ads on older episodes as they continue to be downloaded.$q$, $q$Additional features include listener donations, exclusive subscriber content, a cross-promotion marketplace for finding other shows to swap promotion with, RSS feed import for migrating from another host, and episode transcripts that scale by plan tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc9b345c-46db-4d94-b160-d1e40a0e6d6b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RedCircle's Core plan is free and includes one podcast with unlimited storage, bandwidth, episodes, and downloads. Paid plans start with Growth at 19.99 dollars per month, followed by Pro at 34.99 dollars per month and Enterprise at 119.99 dollars per month, each with a lower effective rate on annual billing.$q$, $q$All paid plans include a 7-day free trial, and higher tiers add multiple podcast support, premium analytics, YouTube distribution, team seats, and a dedicated account manager at the Enterprise level.$q$]::text[], 2);
