-- Enrichment marathon batch: Recruitee, Recruiterflow, Recurly, RecurPost, Red Eclipse 2, Redash, REDAXO, RedCircle

-- ── Recruitee ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based applicant tracking system and collaborative hiring platform that helps growing companies post jobs, source candidates, and manage recruitment pipelines from one dashboard.$q$, short_description),
  pricing_model = COALESCE($q$Tiered subscription with custom, quote-based pricing scaled by employee headcount and plan; annual contracts are required, with a 20 percent discount for paying annually.$q$, pricing_model),
  starting_price = COALESCE($q$Custom quote (pricing not publicly listed for the Start, Advance, and Optimize plans)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$51-200 employees (third-party estimates range up to 500)$q$, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Recruitee Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Recruitee (now Tellent Recruitee) costs, who it is for, and how its ATS and collaborative hiring tools compare before you book a demo.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Recruitee, now operating under the parent brand Tellent as Tellent Recruitee, is a cloud-based applicant tracking system and collaborative hiring platform launched in August 2015 by co-founders Perry Oostdam and Pawel Smoczyk in Amsterdam, Netherlands, where the company remains headquartered today. The platform was built to help small and mid-sized companies move recruitment out of spreadsheets and email threads and into a single shared pipeline, combining job posting distribution to more than 200 marketplace integrations and job boards, a customizable careers site branded as CareersHub, candidate sourcing, structured interview scorecards, and collaborative hiring workflows that let hiring managers, recruiters, and interviewers comment and rate candidates in one place. Recruitee raised early seed funding in September 2015 and grew as an independent Dutch SaaS company before merging in February 2021 with the Finnish HR software provider Sympa, a deal backed by growth equity firm Providence Strategic Growth. The combined group went on to acquire the French company Javelo and the German company kiwiHR in 2022, after which the parent organization was renamed Tellent, with Recruitee continuing to operate as the Tellent Recruitee product line and reportedly serving more than 7,000 companies globally. As of 2026 the product is sold across three tiers, Start, Advance, and Optimize, each scoped by the number of active job postings, careers site sophistication, and access to AI-assisted features such as an AI Screening Assistant and AI Matching Assistant that increase in usage credits at higher tiers; Optimize additionally unlocks single sign-on, requisition approval workflows, fairness and bias-reduction tools, and business intelligence integrations. None of the three tiers list public per-seat or per-employee pricing on the company website; instead, Recruitee requires a minimum one-year contract and quotes prospects based on company headcount and chosen plan, though monthly payment terms are available and annual prepayment earns a 20 percent discount. Optional paid add-ons available on any plan include SMS texting, WhatsApp-based candidate outreach, an onboarding workflow tool called Journeys, and AgencyHub for managing external recruitment agencies. Recruitee's careers site and candidate-facing pages support localization into 17 languages, letting employers present job listings and application flows to candidates in their local language even though the recruiter-facing interface itself is primarily English. Competing directly with tools such as Greenhouse, Lever, BambooHR, and Workable, Recruitee is generally positioned as a mid-market ATS for growing teams that want an all-in-one hiring platform without the implementation overhead of larger enterprise HR suites, though its lack of published pricing and 2024 shift from user-based to employee-count-based billing has drawn some customer criticism around cost transparency heading into 2026.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b1fba57-cd15-424e-804c-46b51d8f4396';

