-- ── Recruiterflow ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Recruitment CRM and applicant tracking system for staffing agencies and executive search firms, combining candidate sourcing, multichannel outreach sequences, and AI-powered recruiting automation.$q$, short_description),
  pricing_model = COALESCE($q$Per-user subscription billed monthly or annually, with a minimum of 3 seats per account$q$, pricing_model),
  starting_price = COALESCE($q$$149/user/month (Platform plan, billed monthly; lower effective rates available on annual billing)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Approximately 64 employees (2026), reported to be roughly doubling over the following year$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Recruiterflow Pricing and Review 2026: Is It Right for Your Agency?$q$, seo_title),
  seo_meta_description = COALESCE($q$An independent look at Recruiterflow's recruitment CRM and ATS, its Platform and AIRA pricing plans, key features, and how it compares for staffing agencies.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Recruiterflow is a recruitment customer relationship management and applicant tracking system built specifically for staffing agencies, executive search firms, and recruitment process outsourcing teams. Founded in 2017 and headquartered in San Francisco, California, Recruiterflow has grown as a bootstrapped company without outside venture funding, reportedly crossing roughly 24 million dollars in annual recurring revenue and more than 50 crore Indian rupees in ARR by 2026 while remaining profitable, according to company statements. The company employs approximately 64 people as of 2026 and has said it plans to roughly double headcount over the following year, serving recruiting agencies across more than 90 countries and describing itself as trusted by over 1,700 recruitment agencies. Recruiterflow combines a candidate and client relationship database with sourcing tools, including a Chrome extension for bulk sourcing from LinkedIn and other sites, multichannel outreach sequences across email and other channels, recruiting automation workflows the company calls Recipes, sales automation for business development, client and team access controls, custom reporting, and API access. In 2026 the company markets its pricing around two tiers rather than the multi-tier structure some third-party review sites still reference from earlier years: a Platform plan priced at 149 dollars per user per month that includes the combined ATS and CRM, automation, sequences, sales tools, and reporting; and an AIRA plan at custom pricing that layers in Recruiterflow's AI recruiting agent capabilities, including an AI notetaker that automatically summarizes calls, an AI candidate matchmaker, job-change alerts, automated field updates, submission and task agents, omnichannel communication syncing, and custom business intelligence dashboards. Recruiterflow emphasizes that both plans include unlimited jobs, candidates, contacts, and companies, and states there are no hidden add-on fees, with all current and future AIRA features bundled into that tier at no extra charge. All plans carry a three-seat minimum, and Recruiterflow offers a 14-day free trial with full feature access, including the ability to run a live outbound campaign and import an existing candidate database before committing. The platform holds a reported 4.8-star rating across more than 10,000 recruiter reviews on third-party review sites. Recruiterflow competes most directly with other recruitment CRM and ATS platforms such as Recruit CRM, Bullhorn, and Loxo, and is generally positioned toward recruitment agencies and search firms that need a combined sales-and-hiring pipeline rather than corporate in-house talent acquisition teams, which more often choose enterprise ATS platforms like Greenhouse or Lever instead.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e1cdadd8-bcfb-4fe7-a40d-88b82d009576';

