-- ── Recurly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Enterprise subscription management and recurring billing platform that automates billing, payments, dunning, and revenue recognition for subscription-based businesses.$q$, short_description),
  pricing_model = COALESCE($q$Tiered subscription combining a base platform fee with a percentage of billing volume; higher tiers require a 1 million dollar minimum annual billing volume, with custom enterprise pricing available.$q$, pricing_model),
  starting_price = COALESCE($q$$249/month plus 0.9 percent of billing volume (Starter plan, first $40,000 in monthly volume included)$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$201-500 employees (estimates vary from roughly 280 to 350+ across data providers)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (additional offices in Boulder, New Orleans, and London)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Recurly Pricing and Review 2026: Subscription Billing Platform Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$What Recurly costs, who owns it, and how its subscription billing, churn prevention, and revenue recognition tools stack up for growing SaaS and DTC businesses.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Recurly is a subscription management and recurring billing platform founded in September 2009 in San Francisco, California, by Isaac Hall, Dan Burkhart, and Tim Van Loan, and it remains headquartered in San Francisco today with additional offices in Boulder, New Orleans, and London. The company raised early venture funding, including a 1.6 million dollar seed round led by Polaris Partners in 2010, before undergoing a significant ownership change in 2020 when the technology-focused private equity firm Accel-KKR made a majority equity investment, a deal that closed and was more broadly announced through 2021; Recurly has continued operating under Accel-KKR's backing since. Over its history Recurly has also acquired smaller companies including Redfast, Prive, and LeapRev to extend its churn-prevention and analytics capabilities. As of 2026 Recurly reports several hundred employees, with LinkedIn listing the company in the 201 to 500 employee range and other data providers citing figures between roughly 280 and 350. The platform's core product handles automated global subscription billing, flexible plan and pricing configuration, static and AI-powered churn-prevention tools, dunning campaigns for failed payments, support for more than 10 payment methods and more than 20 payment gateways, multicurrency support, and single sign-on on higher tiers. Recurly's published pricing starts with a Starter plan at 249 dollars per month plus 0.9 percent of billing volume, with the first 40,000 dollars of monthly volume included; above that, an All-Access plan is priced at under 1 percent of billing volume but requires a minimum of 1 million dollars in annual billing volume and is billed annually, adding AI-powered churn prediction agents, advanced analytics, payments orchestration, custom reporting, and SSO. A dedicated All-Access for Shopify plan targets Shopify merchants launching subscription products, adding features like customizable bundles, subscribe-and-save flows, prepaid and gift subscriptions, and a hosted, passwordless subscriber portal. Recurly also sells two adjacent products beyond core billing: Engage, an AI-driven retention and churn-prediction tool starting at 1,600 dollars per month billed annually, and RevRec, an automated revenue recognition and compliance product starting at 850 dollars per month billed annually for handling contract modifications, standalone selling price automation, and multi-GAAP compliant revenue reporting. Recurly primarily competes with subscription billing platforms such as Chargebee, Zuora, and Stripe Billing, and is generally positioned toward mid-market and larger subscription businesses with meaningful payment volume, given its percentage-of-revenue pricing model and 1 million dollar minimum for its highest self-serve-adjacent tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2899eedd-31f8-47bb-91c7-6b9e3cb0215b';

