-- ── RecurPost ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Social media scheduling and management platform for small businesses, agencies, and marketers, offering recurring content libraries, bulk CSV scheduling, and multi-client workspaces.$q$, short_description),
  pricing_model = COALESCE($q$Tiered monthly or annual subscription based on number of connected social accounts and users; no permanent free plan, but a 14-day free trial is offered.$q$, pricing_model),
  starting_price = COALESCE($q$$9/month (Starter plan, billed monthly)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Winder, Georgia, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$RecurPost Pricing and Review 2026: Social Media Scheduler Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$RecurPost's Starter, Personal, Agency, and Enterprise pricing, recurring-post features, and how it compares for solo marketers and social media agencies.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RecurPost is a social media scheduling and management platform founded in 2016 by Dinesh Agarwal and headquartered in Winder, Georgia, in the United States. The company has grown into a bootstrapped social media tool used by a reported 100,000-plus businesses, with data from Latka indicating it reached roughly 5.3 million dollars in annual revenue and around 60,000 customers by 2024, and founder interviews citing annualized revenue closer to 27 million dollars in more recent reporting; company size estimates place the team at roughly 11 to 50 employees. RecurPost's signature feature, reflected in its name, is recurring or evergreen content scheduling: users can build libraries of approved posts that automatically republish on a set cadence, alongside standard one-off scheduling, a visual content calendar, and a best-time-to-post scheduler. The platform connects to ten networks, including Facebook, Instagram, LinkedIn, X, Google Business Profile, Pinterest, TikTok, YouTube, Threads, and Bluesky, and includes a composer with a built-in image editor, AI-generated captions and images, hashtag suggestions, and a royalty-free stock image library. For agencies, RecurPost supports separate client workspaces, password-free client onboarding, internal and external approval workflows, white-label analytics reporting, and bulk post scheduling via CSV import with no stated upload limit. As of 2026, RecurPost sells four self-serve and custom tiers, all backed by a 14-day free trial requiring no credit card: Starter at 9 dollars per month for 2 social accounts and 1 user; Personal at 25 dollars per month for 5 accounts with platform-specific post customization; Agency at 79 dollars per month for 20 accounts, 3 users, client workspaces, and white-label reporting; and a custom-priced Enterprise tier for 100 or more accounts with dedicated support. Annual billing saves roughly two months' cost compared with paying monthly, additional social accounts can be added a la carte for 4 dollars per month, and extra teammate seats on the Agency plan cost 20 dollars per month. RecurPost previously offered a permanent free plan but discontinued it, moving fully to paid tiers backed by a trial period instead. The company backs new subscriptions with a 30-day money-back guarantee and supports billing in more than 30 currencies. RecurPost is most often compared with other social scheduling tools such as Buffer, Hootsuite, Later, and Publer, and is generally positioned toward solo marketers, small businesses, and social media agencies managing multiple client accounts who want lower-cost recurring-content scheduling rather than full enterprise social suites.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '410b0dd0-b940-4829-8aac-3c86129e1d0d';

