-- ── Red Eclipse 2 ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source first-person arena shooter with fast parkour-style movement, built on the Tesseract engine and featuring a built-in real-time multiplayer level editor.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Red Eclipse 2 Overview 2026: Free Open-Source FPS Game Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$What Red Eclipse 2 is, how its parkour-focused arena shooter and Tesseract engine work, and why the game is completely free and open source.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Red Eclipse is a free, open-source first-person shooter originally forked from Cube 2: Sauerbraten, developed by an open community of contributors led by developers including Quinton Reeves, Lee Salzman, and Slawomir Blauciak. The project's first stable release, version 1.0 nicknamed the Ides Edition, launched on March 15, 2011, and the game continued receiving numbered updates through the following years, adding modes like King of the Hill and Coop in version 1.3 in 2012 and reaching version 1.6, the Sunset Edition, on December 21, 2017, which was the last release built on the original Cube 2-derived rendering engine. Red Eclipse 2.0, subtitled the Jupiter Edition, represented a major technical overhaul: it moved the game onto the Tesseract engine, a separate, more advanced fork of Cube 2 written by Lee Salzman, and was released on Steam on December 19, 2019, listed there simply as Red Eclipse 2. The Tesseract engine brought substantially improved graphics to the series, including deferred shading, better shadow mapping, and reflection and refraction support, while the game retained its defining identity as a fast-paced, agile arena shooter built around parkour-style movement, letting players run, jump, wall-run, and slide through vertical multiplayer maps rather than relying purely on traditional run-and-gun combat. Like its Cube 2 lineage, Red Eclipse ships with a full real-time, in-game level editor, giving players the same tools the developers use to build and modify maps, and the game supports numerous competitive modes across free-for-all and team-based play. Critically, Red Eclipse is entirely free to download and play, has no premium tier, in-game purchases, or subscription, and is distributed as free and open-source software under the permissive zlib license, meaning its full source code is publicly available for anyone to inspect, modify, and redistribute. It is available on Steam as well as through itch.io and direct downloads from the official redeclipse.net website, and runs on Windows, macOS, and Linux. Because it is a community-maintained open-source project rather than a commercial studio product, Red Eclipse has no corporate headquarters, no disclosed employee count, and no venture funding; development and ongoing updates are driven by volunteer contributors. It is frequently referenced in roundups of the best free and open-source FPS games alongside titles like Xonotic and OpenArena, and its emphasis on movement-based skill and level-editing tools has earned it a small but dedicated competitive and modding community since its debut.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '59de2787-72b5-4f39-9d09-b260b1994aa6';

