-- ── Redash ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source data visualization and dashboard tool that connects to many databases and APIs for writing SQL queries and building shareable dashboards; acquired by Databricks in 2020.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source for self-hosted deployments; the original hosted Redash Cloud service was discontinued by Databricks in 2021.$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Originally Rehovot, Israel; the project is now maintained under Databricks, headquartered in San Francisco, California$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Redash in 2026: Is It Still Free, Maintained, and Worth Using?$q$, seo_title),
  seo_meta_description = COALESCE($q$Redash's open-source status after the Databricks acquisition, whether the hosted version still works, self-hosting costs, and core dashboard features explained.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Redash is an open-source data visualization and dashboarding tool created in 2013 by Israeli developer Arik Fraimovich, originally out of Rehovot, Israel, to let teams connect to a wide range of databases and APIs, write and share SQL queries, visualize results as charts, and assemble them into shareable dashboards without needing a dedicated business intelligence team. The project grew an open-source community around it, with its GitHub repository accumulating roughly 28,000 to 29,000 stars, and reportedly counted companies such as Atlassian, Cloudflare, Mozilla, and SoundCloud among its users, alongside a paid hosted version of the software. In June 2020, at its Spark and AI Summit, Databricks announced it had acquired Redash, with the deal's financial terms undisclosed; Databricks framed the acquisition as extending Redash's open-source visualization and dashboard capabilities and integrating a hosted version directly into the Databricks platform, positioning Redash alongside other open-source projects in its portfolio such as Apache Spark, Delta Lake, and MLflow. Following the acquisition, however, Databricks shut down the original hosted Redash Cloud service at app.redash.io on November 30, 2021, with user data permanently deleted roughly a month later, on December 30, 2021. The open-source, self-hosted version of Redash has continued to exist and remains free to deploy, but development has slowed considerably since the acquisition, with the project averaging roughly one release per year from 2022 onward, leading many in the community to describe it as being in maintenance mode rather than active development; some contributors have also formed community-led continuations of the project on GitHub. Because Redash is open source, self-hosting it carries no licensing fee, only infrastructure hosting costs, which most estimates put at roughly 5 to 10 dollars per month for a small to medium instance depending on the chosen database and usage scale; third-party managed-hosting providers separately offer paid Redash hosting plans, typically starting around 49 dollars per month, though these are unaffiliated with Databricks. As of 2026, teams evaluating Redash should treat it primarily as a mature but slow-moving open-source self-hosted BI tool rather than an actively growing commercial product, and many organizations that adopted it for lightweight SQL-based dashboards have migrated toward Databricks' own native dashboarding tools or alternatives like Metabase and Apache Superset for continued active development.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b4fe35bb-b786-4c89-83e9-c43385bfe93b';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'b4fe35bb-b786-4c89-83e9-c43385bfe93b' AND logo IS NULL AND website IS NOT NULL;

