-- ── REDAXO ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source PHP content management system from Germany, giving developers full control over templates, modules, and multilingual website structures.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Frankfurt am Main, Germany (home of lead maintainer Yakamara Media)$q$, headquarters),
  languages = ARRAY[$q$German$q$, $q$English$q$, $q$Spanish$q$, $q$Italian$q$, $q$Swedish$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$REDAXO CMS Review 2026: Free Open-Source PHP CMS Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$What REDAXO is, who maintains it, its module-based architecture, multilingual support, and why it is completely free under the MIT license.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$REDAXO is a free, open-source content management system built on PHP, originally developed internally starting in 1999 by the German web agency Yakamara, based in Frankfurt am Main, before being released publicly as open-source software in 2004 under the GNU General Public License. In 2016, the project switched to the more permissive MIT license, which it continues to use today, allowing REDAXO to be freely downloaded, modified, and used commercially by anyone without licensing fees. Development is led by Yakamara's core team alongside Friends of REDAXO, a volunteer association of several dozen independent web developers and agencies who contribute modules, translations, and core improvements, making REDAXO a community-driven project rather than a single-vendor commercial product. Technically, REDAXO runs on PHP and stores content in a MySQL or MariaDB database, and it is distributed through GitHub under the redaxo/redaxo repository as well as via Composer for PHP dependency management. Its architecture centers on a modular structure: developers build custom content modules and templates with full control over HTML, CSS, and PHP output, separating layout from content so that non-technical editors can update pages without touching code once modules are built. Core platform capabilities include support for fully multilingual websites and content trees, structured media and file management, a granular, configurable user rights and role system that lets administrators define precisely what each backend user can see and edit, and straightforward installation aimed at professional web developers and agencies rather than end consumers looking for a drag-and-drop site builder. The REDAXO backend interface itself is available in several languages beyond its native German, including English, Spanish, Italian, Swedish, and Portuguese, reflecting the project's roots as a German tool that has since built an international user base, particularly across German-speaking Europe where it remains most widely adopted. Because it is entirely free and open source, REDAXO has no pricing tiers, subscription plans, or paid editions; instead, the ecosystem around it is supported by community contributions, sponsorships, and paid implementation or hosting services offered independently by web agencies that specialize in the CMS, similar to how WordPress or Drupal service providers operate. REDAXO is most commonly compared with other open-source, developer-focused PHP content management systems such as Contao and Neos, and it is generally chosen by freelance developers and small-to-mid-size agencies, especially in Germany, Austria, and Switzerland, who want a lightweight, highly customizable CMS core without the bloat or licensing costs of larger commercial platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bfc00fd3-6190-4930-b4d3-4453015d69ed';

