-- ── RedCircle ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Podcast hosting and monetization platform offering a free unlimited-storage tier alongside paid plans with dynamic ad insertion, an ad marketplace, and cross-promotion tools for independent podcasters.$q$, short_description),
  pricing_model = COALESCE($q$Freemium tiered subscription (free Core plan plus paid Growth, Pro, and Enterprise tiers), billed monthly or annually, with a 7-day free trial on paid plans.$q$, pricing_model),
  starting_price = COALESCE($q$Free (Core plan); paid plans start at $19.99/month (Growth plan), or $180/year (about $14.99/month) billed annually$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Roughly 19-49 employees (estimates vary by source)$q$, company_size),
  headquarters = COALESCE($q$Los Angeles, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$RedCircle Pricing and Review 2026: Podcast Hosting and Monetization Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$RedCircle's free Core plan, Growth, Pro, and Enterprise pricing, dynamic ad insertion, and monetization splits explained for independent podcasters.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RedCircle is a podcast hosting and monetization platform founded in 2018 by Mike Kadin and Jeremy Lermitte, former Uber and Facebook employees, and headquartered in Los Angeles, California. The company raised a 6 million dollar Series A funding round co-led by EPIC Ventures and Refinery Ventures, with participation from investors including SignalFire, Bloomberg Beta, and MathCapital, and has been reported to have raised between roughly 7.5 million and 9.5 million dollars in total funding across different data providers; employee count estimates place the team at roughly 19 to 49 people depending on the source and date. RedCircle differentiates itself from many podcast hosts by offering a genuinely free Core plan that includes one podcast with unlimited storage, bandwidth, episodes, and downloads, distribution to all major listening platforms, access to listener donations and exclusive subscriber content, standard analytics, and eligibility to join the RedCircle Ad Platform once a show reaches 500 or more weekly downloads. The RedCircle Ad Platform is the company's built-in advertising marketplace, offering both host-read and programmatic ad opportunities; podcasters keep 70 percent of revenue from host-read ads and 50 percent from programmatic ads placed through the platform, among the more creator-favorable splits in the podcast hosting industry. Above the free Core tier, RedCircle sells three paid plans as of 2026: Growth, at 19.99 dollars per month or 180 dollars billed annually, which adds support for multiple podcasts, AI video generation, 5 monthly episode transcripts, a cross-promotion marketplace for finding other podcasters to swap audience promotion with, and dynamic ad insertion technology that automatically swaps in new ads on older episodes as they continue to be downloaded; Pro, at 34.99 dollars per month or 360 dollars annually, which adds premium analytics, YouTube distribution, 50 monthly transcripts, and team seats for up to five additional users; and Enterprise, at 119.99 dollars per month or 1,199 dollars annually, which adds a dedicated account manager, comprehensive analytics, and 500 monthly transcripts. All paid plans include a 7-day free trial, and plan changes are handled with prorated billing. RedCircle also supports importing an existing show via RSS feed to migrate from another host without losing episode history. The platform is most commonly compared with other independent podcast hosts such as Buzzsprout, Captivate, and Podbean, and is generally positioned toward independent and semi-professional podcasters who want built-in advertising and monetization tools bundled directly into their hosting plan rather than needing a separate ad sales relationship.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fc9b345c-46db-4d94-b160-d1e40a0e6d6b';

